import React, { Component } from "react";
import "./nav.css";

function Nav() {
  menu = () => {
    return (
      <div className="pushMenu">
        <ul>
          <li src="#">Home</li>
          <li src="#">Portfolio</li>
          <li src="#">Contact</li>
          <li src="#">About me</li>
        </ul>
      </div>
    );
  };
  return <div className="gg-menu-grid-o"></div>;
}
export default Nav;
